<?php

use admin\logic\Product\ProductPrice;
use common\logic\Eshop\Eshop;
use user\logic\UserClientSession;
use user\logic\UserSettings;

/**
 * Admin_Model_WishList
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 * 
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
 * @author     ##NAME## <##EMAIL##>
 * @version    SVN: $Id: Builder.php 7490 2010-03-29 19:53:27Z jwage $
 */
class Admin_Model_WishList extends Admin_Model_Base_WishList {

    const WISHLIST_HASH = 'wishListHash';

    /**
     * @param int|null $userID
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getWishListItems(?int $userID): array {
        $eshop = Eshop::getInstance()->getEshop();
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_WishList object');
        $query->addSelect('object.*, product.*, productEshops.*, vat.*, productLangs.*, productLangs.Name as ProductName, productImages.*, file.*, categories.*');
        $query->addSelect('productLangs.Name as ProductName, productLangs.slug as slug');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());
        $query->leftJoin('object.product product');
        $query->leftJoin('product.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('product.categories categories');
        $query->leftJoin('productImages.file file');
        $query->addGroupBy('object.ID');
        $wishListItems = $query->execute()->toArray();

        foreach ( $wishListItems as &$wishListItem ) {
            $wishListItem['product'] ['CategoryIDs'] = $wishListItem['CategoryIDs'];
            $productPrice = new ProductPrice($wishListItem['product'], UserSettings::getInstance($userID)->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts());
            $wishListItem['product'] = $productPrice->getProduct();
        }

        return $wishListItems;
    }


    /**
     * @param int|null $userID
     * @param int $productID
     * @return bool|Admin_Model_WishList
     */
    public static function getWishListByProductID(?int $userID, int $productID): bool|Admin_Model_WishList {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_WishList object');
        $query->where('object.Product_ID = ?', $productID);

        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());

        return $query->fetchOne();
    }

    /**
     * @param ?int $userID
     * @param int $productID
     * @return Admin_Model_WishList
     */
    public static function createWishlist(?int $userID, int $productID): Admin_Model_WishList {
        $wishList = self::getWishListByProductID($userID, $productID);
        if (!$wishList) {
            $wishList = new Admin_Model_WishList();
            $wishList->Product_ID = $productID;
            $wishList->DateAdded = date('Y-m-d H:i:s');
            if ($userID)
                $wishList->User_ID = $userID;

            $wishList->SessionID = self::getCookieId();
            $wishList->save();
        }
        return $wishList;
    }

    /**
     * @param int|null $userID
     * @param int $productID
     */
    public static function deleteWishListItem(?int $userID, int $productID): void
    {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_WishList object');
        $query->where('object.Product_ID = ?', $productID);

        if ( $userID )
            $query->andWhere('object.User_ID = ?', $userID);
        else
            $query->andWhere('object.SessionID = ?', self::getCookieId());
        $query->execute();
    }

    /**
     * @param Eshop|null $eshop
     */
    public static function updateWishListAfterLogin(): void {
        $userID = UserClientSession::getCurrentUserID();

        $query = Doctrine_Query::create();
        $query->update('Admin_Model_WishList object');
        $query->set('object.User_ID', '?', $userID);
        $query->where('object.SessionID = ?', self::getCookieId());
        $query->execute();
    }


    /**
     * @return string
     */
    public static function getCookieId(): string {
        return $_COOKIE[self::WISHLIST_HASH] ?? self::getNewCookieId();
    }

    /**
     * @return string
     */
    protected static function getNewCookieId(): string {
        setcookie(self::WISHLIST_HASH, $id = md5(time()), strtotime('+30 day'), '/', null, false, true);

        return $id;
    }
}